const express = require('express');
const app = express();
const { randomUUID } = require('node:crypto');
const { sendError } = require('../../lib/errors');

// Middleware to parse JSON bodies
app.use(express.json());

// Health check endpoint
app.get('/health', (req, res) => {
  res.json({ ok: true });
});

// Project routes
const projectsRouter = require('./modules/projects/routes');
app.use('/projects', projectsRouter);

module.exports = app;

const express = require('express');
const router = express.Router();
const { getProjectById } = require('./service');

// Get project by ID
router.get('/:projectId', async (req, res) => {
  const project = await getProjectById(req.params.projectId);
  if (!project) return sendError(res, 404, 'E_NOTFOUND', 'Project not found');
  res.json({ project });
});

module.exports = router;

const { randomUUID } = require('node:crypto');
const projects = {}; // In-memory storage for simplicity

// Get project by ID
exports.getProjectById = (projectId) => {
  return projects[projectId];
};

// Add new project
exports.addProject = ({ name }) => {
  if (!name) return null;
  const id = randomUUID();
  projects[id] = { id, name };
  return { id, name };
};

const http = require('http');
const app = require('./app');

const server = http.createServer(app);

module.exports = app;

const express = require('express');
const router = express.Router();
const taskService = require('./service');

router.post('/:projectId/tasks', async (req, res) => {
  const { projectId } = req.params;
  const { title, status } = req.body;
  if (!title || !status) return sendError(res, 400, 'BAD_REQUEST', 'Title and status are required');
  try {
    const task = await taskService.createTask({ projectId, title, status });
    res.status(201).json({ task });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_SERVER_ERROR', error.message);
  }
});

module.exports = router;

const { v4: uuidv4 } = require('uuid');
const tasks = [];

exports.createTask = ({ projectId, title, status }) => {
  const task = { id: uuidv4(), projectId, title, status };
  tasks.push(task);
  return task;
};

