const express = require('express');
const router = express.Router();
const commentService = require('./service');

router.post('/:projectId/tasks/:taskId/comments', async (req, res) => {
  const { projectId, taskId } = req.params;
  const { message } = req.body;
  if (!message) return sendError(res, 400, 'BAD_REQUEST', 'Message is required');
  try {
    const comment = await commentService.addComment({ projectId, taskId, message });
    res.status(201).json({ comment });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_SERVER_ERROR', error.message);
  }
});

module.exports = router;

const { v4: uuidv4 } = require('uuid');
const comments = [];

exports.addComment = ({ projectId, taskId, message }) => {
  const comment = { id: uuidv4(), projectId, taskId, message };
  comments.push(comment);
  return comment;
};

exports.sendError = (res, status, code, message) => {
  res.status(status).json({ error: { code, message } });
};
